package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testGenerateNonExecutableJson_setsFlagAndReturnsThis() throws Exception {
    // Initially the field generateNonExecutableJson should be default false or DEFAULT_JSON_NON_EXECUTABLE (usually false)
    Field flagField = GsonBuilder.class.getDeclaredField("generateNonExecutableJson");
    flagField.setAccessible(true);
    boolean initialValue = flagField.getBoolean(gsonBuilder);

    // Call the focal method
    GsonBuilder returned = gsonBuilder.generateNonExecutableJson();

    // Verify the returned object is the same instance (this)
    assertSame(gsonBuilder, returned);

    // Verify the internal flag is set to true
    boolean updatedValue = flagField.getBoolean(gsonBuilder);
    assertTrue(updatedValue);

    // If the initial value was true, the test still holds because it is set to true again
    // But typically initialValue is false, so we verify it changed
    if (!initialValue) {
      assertNotEquals(initialValue, updatedValue);
    }
  }
}
